from flask import Flask, request, render_template

app = Flask(__name__)

@app.route('/welcome')
def welcome():
    user_data = {
        'name': request.args.get('name', "Guest"),
        'bio': request.args.get('bio', "No bio provided."),
        'location': request.args.get('location', "No location provided."),
        'status': request.args.get('status', "No custom status message.")
    }

    # Replace the following template string with your actual HTML template file path
    html_template = """
    <!DOCTYPE html>
    <html lang="en">
      <head>
        <meta charset="UTF-8" />
        <title>Welcome</title>
      </head>
      <body>
        <h1>Welcome, {name}!</h1>
        <h2><strong>Bio:</strong> {bio}</h2>
        <h3><em>Location:</em> {location}</h3>
        <h4><strong>Status:</strong> {status}</h4>
      </body>
    </html>
    """

    # Replace the following with your actual HTML template rendering function
    rendered_template = render_template(template_name='welcome.html', name=user_data['name'], bio=user_data['bio'], location=user_data['location'], status=user_data['status'])
    return rendered_template

if __name__ == "__main__":
    app.run(debug=True)